window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2021>1>a>i","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Study  specimen A, B and C and answer questiions 1(a) to 1(c).    Name the part of the body where specimens A, B and C would be found in a mammal.","images":[],"marking_scheme":"A: Neck region/neck  B: Chest region/thoracic region/thorax  C: Upper abdominal region/upper abdomen","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>1>a>ii","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"State one function each of specimens A, B and C","images":[],"marking_scheme":"A: Supports the head/head region - protects blood vessels   - protects spinal cord   - passage for blood vessel   - passage fpr spinal cord   - provides surface for attachment of neck muscles.      B: Provides point of attachment for chest muscles /articulates with rib bones   - protects the/passage of spinal cord.   C: Bears weight of the body   - permits bending/sideways movement/rotation of the body   - provides surface for attachment of muscles   -protects the spinal cord/passage of spinal cord.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>1>b>i","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Make a drawing , 6cm to 8cm long of the anterior view of specimen C and label fully","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing/Diagram of anterior view of specimen C/lumbar vertebra","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2021>1>b>ii","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"State one function each of four of the parts labelled in 1(b)(i).","images":[],"marking_scheme":"Neural spine: for attachment of (abdominal and back ) muscles  Transverse process: For muscle attachment   Neural arch: For muscle attachment/protection of spinal cord  Centrum: Provides (mechanical) support  Neural canal: Encloses/Houses the spinal cord/passage for spinal cord.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>1>c>i","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Mention the total number of each of specimens A, B and C in adult humans","images":[],"marking_scheme":"A: Cervical vertebra (7) B: Thoracic vertebra (12) C: Lumbar vertebra (5)","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>1>c>ii","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Name two other vertebrae in humans.","images":[],"marking_scheme":"Sacral/sacrum - caudal/coccyx","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2021>2>a","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : GROWTH","question":"*inst*  Beakers D, E, F and G contain seeds that have been sown for seven days. Carefully remove one seed/seedling from each of the beakers labelled D, E, F and place each on the corresponding white tile labelled D, E, F and G. Study them and answer questions 2(a) to 2(c).Observe the soils and seed/seedling then record the observation and result on the table below.  Soil/seed/seedling in beakerTwo observationResultDEFG","images":[],"marking_scheme":"Soil/seed/seedling in the beakerTwo observationsResultD-Cotyledons split open;-emergence of radicle/presence of epicotyl;-presence of foilage leaves/stem/hypocotyl and epicotyl moist soilGermination occurredE-Seeds/cotyledons are separate/split;-The seeds/cotyledons are brown;-The seeds/cotyledons are decaying;-the seeds/cotyledons have no testa.-The seeds have no embryo/plumule and radicle.-Moist soilNo germinationF-The seeds are brown;-Testa intact;-The seeds are smooth.-The seeds are soft.-Moist soil/oil presentNo germinationG-The seeds are intact;-The seeds have brown/white testa;The seeds are hard;-The soil is dry OR -Radicle/root present;-Cotyledon split;-Plumule present;-The soil is dry No germination OR Delayed/slow germination","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>2>b>i","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"i","group":"","topic":"SOIL","question":"Name one condition for germination that was likely absent in the beakers labelled E, F and G","images":[],"marking_scheme":"E: Viable seed F: Oxygen/viable seed G: Moisture/water","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>2>b>ii","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : GROWTH","question":"Give two reasons for the result in beaker D.","images":[],"marking_scheme":"All the conditions of water, oxygen/air, warmth/suitable temperature, viable seed necessary for germination were present;   - it is the control experiment.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>2>c","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : GROWTH","question":"Make a drawing 8cm to 10cm long of one seed/seedling obtained from the beaker labelled D and label fully.","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing/Diagram of seedling obtained from the beaker labelled D","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>3>a>i","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Study specimens L and M and answer questions 4(a) to 4(e).   Classify each of specimens L and M into its: Phylum L: ________ M: _______","images":[],"marking_scheme":"Phylum L: Arthropoda M: Arthropoda","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>3>a>ii","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Classify each of specimens L and M into its: Class L: ________ M: _______","images":[],"marking_scheme":"Class: L:Insecta: M: Insecta","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>3>b>i","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"State three observable features of members of the class of specimen L.","images":[],"marking_scheme":"Observable Features of Members of the Class of Specimen L:  -Three body divisions: head, thorax, abdomen;  -Three pairs of jointed walking legs;  -Presence of wings;  -A pair of jointed antennae   -Spiracles present;  - A pair of compound eyes;   -Exoskeleton of chitin/chitinous exoskeleton.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>3>b>ii","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Name three other classes of the phylum to which specimen L belongs.","images":[],"marking_scheme":"Other classes of phylum of specimen L:-Crustacea  -Chilopoda  -Diplopoda  -Arachnida.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>3>c>i","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"i","group":"","topic":"APPLICATION OF VARIATIONS :","question":"State two ways each by which specimens L and M are of economic importance.","images":[],"marking_scheme":"Economic Importance of Specimen: (i) L:   -Vector/transmits diseases;   -Buzzing noise disturbs(sleep)-Causes discomfort through its bites. M:   -Has aesthetic value/used as ornament, Pollinates flowers:   -Destroys(citrus) fruits by feeding on them","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>3>c>ii","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"ii","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS","question":"State five ways by which specimen L can be controlled.","images":[],"marking_scheme":"Ways by which Specimen L/Mosquito can be Controlled   -Sleeping under nets ( to prevent adult mosquito bites); Clearing the bushes around the house ( to eliminate places where mosquitoes hide and breed);   -Removing all stagnant water bodies around the house ( to prevent mosquitoes from breeding);   -Using/spraying insecticides in the rooms/around the house (to kill adult mosquitos)   -Pouring oil on stagnant water bodies (to suffocate the larvae),  -Introducing fish/bacteria, e.g. Bacillus species into water bodies (to eat up mosquito larvae and pupae);   -Using mosquito repellents(to prevent adult mosquitos from biting);   -Using light to attract and kill adult mosquitoes/use of mosquito trap:   -Using genetically modified mosquitoes to result in early death","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>3>d>i","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"i","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS","question":"State five observable differences between specimens L and M.","images":[],"marking_scheme":"L/MosquitoM/ButterflyAntennae are featheryAntennae are not featheryAntennae are taperedAntennae are clubbed/club shapedWings without colour patchesWings with colour patchesProboscis pointedProboscis coiledHalters/Halteres presentHalters/Halteres absentRelatively small/smallerRelatively  big/biggerDull coloured/ash colouredBeautifully coloured/multicolouredOne pair of wingsTwo pair of wingsNervure absent on wingsNervure present on wingsEye spot absent on wingsEye spot present on wings","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>3>d>ii","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"State four observable similarities between specimens L and M.","images":[],"marking_scheme":"Similarities between specimens L and M: Both have   -three body divisions/head, thorax and abdomen  -proboscis;   -wings:   -Six legs/three pairs of legs:  - one pair of compound eyes;   - one pair of antennae   - Exoskeleton of chitin chitinous exoskeleton;   - Segmented abdomens   - three thoracic segments.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2021>3>e","subject":"Biology Practical","year":"2021","type":"Practical","sub_label":"e","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Name one habitat each of specimens L and M","images":[],"marking_scheme":"Habitat of specimens L and M:   L: Houses/land/swamp/marshy areas/ dark places/tall grasses/ pond(s)   M: Garden/on trees/leaves/flowers/rock surfaces/bare ground/grassland","marks":"1","difficulty":"2"}];